// app/tools/editing-n3/components/modals/n3-inventory-detail-modal.tsx
/**
 * 棚卸し商品詳細モーダル
 * 
 * inventory_master の商品詳細を表示・編集するモーダル
 * 原価と在庫数のインライン編集に対応
 * L4属性（販売予定販路）とその他経費の編集に対応
 */

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { X, Package, DollarSign, Hash, Calendar, Edit2, Save, ExternalLink, Check, Loader2, Plus, Trash2, Store } from 'lucide-react';
import { N3Button, N3Divider } from '@/components/n3';
import type { InventoryProduct } from '../../hooks';
import { SALES_CHANNEL_LABELS, COST_ITEM_PRESETS, type SalesChannel, type AdditionalCosts } from '@/types/inventory';
import { supabase } from '@/lib/supabase/client';

interface N3InventoryDetailModalProps {
  product: InventoryProduct | null;
  isOpen: boolean;
  onClose: () => void;
  onSave?: (id: string, updates: Partial<InventoryProduct>) => Promise<void>;
  onStockChange?: (id: string, newQuantity: number) => Promise<void>;
  onCostChange?: (id: string, newCost: number) => Promise<void>;
  onRefresh?: () => void;
}

// 経費項目の型
interface CostItem {
  key: string;
  label: string;
  amount: number;
}

export function N3InventoryDetailModal({
  product,
  isOpen,
  onClose,
  onSave,
  onStockChange,
  onCostChange,
  onRefresh,
}: N3InventoryDetailModalProps) {
  const [localProduct, setLocalProduct] = useState<InventoryProduct | null>(null);
  
  // 各フィールドの編集状態
  const [editingStock, setEditingStock] = useState(false);
  const [editingCost, setEditingCost] = useState(false);
  
  // 編集中の値
  const [stockValue, setStockValue] = useState<string>('');
  const [costValue, setCostValue] = useState<string>('');
  
  // 保存中の状態
  const [savingStock, setSavingStock] = useState(false);
  const [savingCost, setSavingCost] = useState(false);
  
  // L4属性（販売予定販路）
  const [selectedChannels, setSelectedChannels] = useState<SalesChannel[]>([]);
  const [savingChannels, setSavingChannels] = useState(false);
  
  // その他経費
  const [costItems, setCostItems] = useState<CostItem[]>([]);
  const [savingCostItems, setSavingCostItems] = useState(false);
  const [newCostKey, setNewCostKey] = useState('');
  const [newCostAmount, setNewCostAmount] = useState('');

  // 商品データをローカルにコピー
  useEffect(() => {
    if (product) {
      setLocalProduct({ ...product });
      setStockValue(String(product.physical_quantity || 0));
      setCostValue(String(product.cost_jpy || product.cost_price || 0));
      
      // L4属性を設定
      const l4 = (product as any).attr_l4;
      setSelectedChannels(Array.isArray(l4) ? l4 : []);
      
      // その他経費を設定
      const additionalCosts = (product as any).additional_costs || {};
      const items: CostItem[] = [];
      for (const [key, amount] of Object.entries(additionalCosts)) {
        const preset = COST_ITEM_PRESETS.find(p => p.key === key);
        items.push({
          key,
          label: preset?.label || key,
          amount: Number(amount) || 0,
        });
      }
      setCostItems(items);
    }
  }, [product]);

  // モーダルが閉じられた時に編集状態をリセット
  useEffect(() => {
    if (!isOpen) {
      setEditingStock(false);
      setEditingCost(false);
    }
  }, [isOpen]);

  if (!isOpen || !product || !localProduct) return null;

  // 在庫数の保存
  const handleSaveStock = async () => {
    if (!localProduct || !onStockChange) return;
    
    const newQuantity = parseInt(stockValue) || 0;
    if (newQuantity === localProduct.physical_quantity) {
      setEditingStock(false);
      return;
    }
    
    setSavingStock(true);
    try {
      await onStockChange(String(localProduct.id), newQuantity);
      setLocalProduct(prev => prev ? { 
        ...prev, 
        physical_quantity: newQuantity, 
        current_stock: newQuantity 
      } : null);
      setEditingStock(false);
    } finally {
      setSavingStock(false);
    }
  };

  // 原価の保存
  const handleSaveCost = async () => {
    if (!localProduct || !onCostChange) return;
    
    const newCost = parseInt(costValue) || 0;
    const currentCost = localProduct.cost_jpy || localProduct.cost_price || 0;
    if (newCost === currentCost) {
      setEditingCost(false);
      return;
    }
    
    setSavingCost(true);
    try {
      await onCostChange(String(localProduct.id), newCost);
      setLocalProduct(prev => prev ? { 
        ...prev, 
        cost_price: newCost,
        cost_jpy: newCost 
      } : null);
      setEditingCost(false);
    } finally {
      setSavingCost(false);
    }
  };

  // L4属性（販売予定販路）の保存
  const handleSaveChannels = async () => {
    if (!localProduct) return;
    
    setSavingChannels(true);
    try {
      const { error } = await supabase
        .from('inventory_master')
        .update({ attr_l4: selectedChannels })
        .eq('id', localProduct.id);
      
      if (error) throw error;
      
      setLocalProduct(prev => prev ? { ...prev, attr_l4: selectedChannels } as any : null);
      onRefresh?.();
    } catch (err) {
      console.error('販路保存エラー:', err);
    } finally {
      setSavingChannels(false);
    }
  };

  // 販路チェックボックスのトグル
  const toggleChannel = (channel: SalesChannel) => {
    setSelectedChannels(prev => {
      if (prev.includes(channel)) {
        return prev.filter(c => c !== channel);
      } else {
        return [...prev, channel];
      }
    });
  };

  // その他経費の保存
  const handleSaveCostItems = async () => {
    if (!localProduct) return;
    
    setSavingCostItems(true);
    try {
      const additionalCosts: AdditionalCosts = {};
      for (const item of costItems) {
        if (item.amount > 0) {
          additionalCosts[item.key] = item.amount;
        }
      }
      
      const { error } = await supabase
        .from('inventory_master')
        .update({ additional_costs: additionalCosts })
        .eq('id', localProduct.id);
      
      if (error) throw error;
      
      setLocalProduct(prev => prev ? { ...prev, additional_costs: additionalCosts } as any : null);
      onRefresh?.();
    } catch (err) {
      console.error('経費保存エラー:', err);
    } finally {
      setSavingCostItems(false);
    }
  };

  // 経費項目の追加
  const handleAddCostItem = () => {
    if (!newCostKey || !newCostAmount) return;
    
    const amount = parseInt(newCostAmount) || 0;
    if (amount <= 0) return;
    
    const preset = COST_ITEM_PRESETS.find(p => p.key === newCostKey);
    const existingIndex = costItems.findIndex(item => item.key === newCostKey);
    
    if (existingIndex >= 0) {
      // 既存の項目を更新
      setCostItems(prev => prev.map((item, i) => 
        i === existingIndex ? { ...item, amount } : item
      ));
    } else {
      // 新規追加
      setCostItems(prev => [...prev, {
        key: newCostKey,
        label: preset?.label || newCostKey,
        amount,
      }]);
    }
    
    setNewCostKey('');
    setNewCostAmount('');
  };

  // 経費項目の削除
  const handleRemoveCostItem = (key: string) => {
    setCostItems(prev => prev.filter(item => item.key !== key));
  };

  // 経費合計
  const totalAdditionalCosts = costItems.reduce((sum, item) => sum + item.amount, 0);

  // キー入力ハンドラ
  const handleKeyDown = (e: React.KeyboardEvent, type: 'stock' | 'cost') => {
    if (e.key === 'Enter') {
      if (type === 'stock') handleSaveStock();
      else handleSaveCost();
    } else if (e.key === 'Escape') {
      if (type === 'stock') {
        setStockValue(String(localProduct.physical_quantity || 0));
        setEditingStock(false);
      } else {
        setCostValue(String(localProduct.cost_jpy || localProduct.cost_price || 0));
        setEditingCost(false);
      }
    }
  };

  // 画像URL
  const imageUrl = localProduct.image_url || localProduct.images?.[0] || null;

  // 総原価（原価 + 経費）
  const baseCost = localProduct.cost_jpy || localProduct.cost_price || 0;
  const totalCost = baseCost + totalAdditionalCosts;

  return (
    <div 
      className="fixed inset-0 z-[9999] flex items-center justify-center"
      style={{ background: 'rgba(0, 0, 0, 0.6)', backdropFilter: 'blur(4px)' }}
      onClick={onClose}
    >
      <div 
        className="relative w-full max-w-2xl max-h-[90vh] overflow-hidden rounded-lg shadow-xl"
        style={{ background: 'var(--panel)' }}
        onClick={e => e.stopPropagation()}
      >
        {/* ヘッダー */}
        <div 
          className="flex items-center justify-between px-4 py-3 border-b"
          style={{ borderColor: 'var(--panel-border)' }}
        >
          <div className="flex items-center gap-3">
            <Package size={18} style={{ color: 'var(--accent)' }} />
            <span className="font-semibold" style={{ color: 'var(--text)' }}>
              商品詳細
            </span>
            {localProduct.sku && (
              <span 
                className="px-2 py-0.5 rounded text-xs"
                style={{ background: 'var(--highlight)', color: 'var(--text-muted)' }}
              >
                {localProduct.sku}
              </span>
            )}
          </div>
          <button 
            onClick={onClose}
            className="p-1.5 rounded hover:bg-[var(--highlight)]"
            style={{ color: 'var(--text-muted)' }}
          >
            <X size={18} />
          </button>
        </div>

        {/* コンテンツ */}
        <div className="overflow-y-auto" style={{ maxHeight: 'calc(90vh - 120px)' }}>
          <div className="p-4">
            {/* 上部: 画像 + 基本情報 */}
            <div className="flex gap-4 mb-4">
              {/* 画像 */}
              <div 
                className="w-32 h-32 rounded-lg overflow-hidden flex-shrink-0"
                style={{ background: 'var(--highlight)' }}
              >
                {imageUrl ? (
                  <img 
                    src={imageUrl} 
                    alt={localProduct.product_name || ''} 
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <Package size={32} style={{ color: 'var(--text-subtle)' }} />
                  </div>
                )}
              </div>

              {/* 基本情報 */}
              <div className="flex-1 min-w-0">
                <h3 
                  className="text-lg font-medium mb-2 line-clamp-2"
                  style={{ color: 'var(--text)' }}
                >
                  {localProduct.product_name || localProduct.title || '（商品名なし）'}
                </h3>
                
                <div className="grid grid-cols-2 gap-2 text-sm">
                  <div>
                    <span style={{ color: 'var(--text-muted)' }}>SKU:</span>
                    <span className="ml-2" style={{ color: 'var(--text)' }}>
                      {localProduct.sku || '-'}
                    </span>
                  </div>
                  <div>
                    <span style={{ color: 'var(--text-muted)' }}>アカウント:</span>
                    <span 
                      className="ml-2 px-1.5 py-0.5 rounded text-xs"
                      style={{ 
                        background: localProduct.ebay_account?.toLowerCase() === 'mjt' 
                          ? 'rgba(59, 130, 246, 0.1)' 
                          : 'rgba(34, 197, 94, 0.1)',
                        color: localProduct.ebay_account?.toLowerCase() === 'mjt'
                          ? 'rgb(59, 130, 246)'
                          : 'rgb(34, 197, 94)',
                      }}
                    >
                      {localProduct.ebay_account || 'Manual'}
                    </span>
                  </div>
                  <div>
                    <span style={{ color: 'var(--text-muted)' }}>商品タイプ:</span>
                    <span className="ml-2" style={{ color: 'var(--text)' }}>
                      {localProduct.product_type === 'variation_parent' ? 'バリエーション親' :
                       localProduct.product_type === 'variation_member' ? 'バリエーション子' :
                       localProduct.product_type === 'set' ? 'セット商品' : '単品'}
                    </span>
                  </div>
                  <div>
                    <span style={{ color: 'var(--text-muted)' }}>コンディション:</span>
                    <span className="ml-2" style={{ color: 'var(--text)' }}>
                      {localProduct.condition_name || '-'}
                    </span>
                  </div>
                </div>
              </div>
            </div>

            <N3Divider />

            {/* 在庫・価格セクション（編集可能） */}
            <div className="py-4">
              <h4 className="text-sm font-semibold mb-3" style={{ color: 'var(--text)' }}>
                在庫・価格 <span className="text-xs font-normal" style={{ color: 'var(--text-muted)' }}>（クリックで編集）</span>
              </h4>
              <div className="grid grid-cols-3 gap-4">
                {/* 在庫数（編集可能） */}
                <div 
                  className="p-3 rounded-lg cursor-pointer transition-all hover:ring-2 hover:ring-[var(--accent)]"
                  style={{ background: 'var(--highlight)' }}
                  onClick={() => !editingStock && setEditingStock(true)}
                >
                  <div className="flex items-center justify-between mb-1">
                    <div className="flex items-center gap-2">
                      <Hash size={14} style={{ color: 'var(--text-muted)' }} />
                      <span className="text-xs" style={{ color: 'var(--text-muted)' }}>在庫数</span>
                    </div>
                    {editingStock && (
                      <button
                        onClick={(e) => { e.stopPropagation(); handleSaveStock(); }}
                        disabled={savingStock}
                        className="p-1 rounded hover:bg-[var(--panel)]"
                        style={{ color: 'var(--color-success)' }}
                      >
                        {savingStock ? <Loader2 size={14} className="animate-spin" /> : <Check size={14} />}
                      </button>
                    )}
                  </div>
                  {editingStock ? (
                    <input
                      type="number"
                      value={stockValue}
                      onChange={(e) => setStockValue(e.target.value)}
                      onKeyDown={(e) => handleKeyDown(e, 'stock')}
                      onBlur={handleSaveStock}
                      autoFocus
                      className="w-full px-2 py-1 rounded text-xl font-bold text-center"
                      style={{ 
                        background: 'var(--panel)', 
                        color: 'var(--text)',
                        border: '2px solid var(--accent)',
                      }}
                      onClick={(e) => e.stopPropagation()}
                    />
                  ) : (
                    <div 
                      className="text-2xl font-bold text-center"
                      style={{ 
                        color: (localProduct.physical_quantity || 0) > 0 
                          ? 'var(--color-success)' 
                          : 'var(--color-error)' 
                      }}
                    >
                      {localProduct.physical_quantity || 0}
                    </div>
                  )}
                </div>

                {/* 原価（編集可能） */}
                <div 
                  className="p-3 rounded-lg cursor-pointer transition-all hover:ring-2 hover:ring-[var(--accent)]"
                  style={{ background: 'var(--highlight)' }}
                  onClick={() => !editingCost && setEditingCost(true)}
                >
                  <div className="flex items-center justify-between mb-1">
                    <div className="flex items-center gap-2">
                      <DollarSign size={14} style={{ color: 'var(--text-muted)' }} />
                      <span className="text-xs" style={{ color: 'var(--text-muted)' }}>原価（円）</span>
                    </div>
                    {editingCost && (
                      <button
                        onClick={(e) => { e.stopPropagation(); handleSaveCost(); }}
                        disabled={savingCost}
                        className="p-1 rounded hover:bg-[var(--panel)]"
                        style={{ color: 'var(--color-success)' }}
                      >
                        {savingCost ? <Loader2 size={14} className="animate-spin" /> : <Check size={14} />}
                      </button>
                    )}
                  </div>
                  {editingCost ? (
                    <div className="flex items-center">
                      <span className="text-lg font-bold mr-1" style={{ color: 'var(--text)' }}>¥</span>
                      <input
                        type="number"
                        value={costValue}
                        onChange={(e) => setCostValue(e.target.value)}
                        onKeyDown={(e) => handleKeyDown(e, 'cost')}
                        onBlur={handleSaveCost}
                        autoFocus
                        className="w-full px-2 py-1 rounded text-xl font-bold text-right"
                        style={{ 
                          background: 'var(--panel)', 
                          color: 'var(--text)',
                          border: '2px solid var(--accent)',
                        }}
                        onClick={(e) => e.stopPropagation()}
                      />
                    </div>
                  ) : (
                    <div className="text-2xl font-bold text-center" style={{ color: 'var(--text)' }}>
                      ¥{baseCost.toLocaleString()}
                    </div>
                  )}
                  {!editingCost && !baseCost && (
                    <div className="text-xs text-center mt-1" style={{ color: 'var(--text-muted)' }}>
                      未登録
                    </div>
                  )}
                </div>

                {/* 販売価格（表示のみ） */}
                <div 
                  className="p-3 rounded-lg"
                  style={{ background: 'var(--highlight)' }}
                >
                  <div className="flex items-center gap-2 mb-1">
                    <DollarSign size={14} style={{ color: 'var(--text-muted)' }} />
                    <span className="text-xs" style={{ color: 'var(--text-muted)' }}>販売価格</span>
                  </div>
                  <div className="text-2xl font-bold text-center" style={{ color: 'var(--accent)' }}>
                    ${(localProduct.selling_price || 0).toFixed(2)}
                  </div>
                </div>
              </div>
              
              {/* 利益表示（総原価で計算） */}
              {totalCost > 0 && localProduct.selling_price && (
                <div 
                  className="mt-3 p-2 rounded text-sm text-center"
                  style={{ background: 'rgba(34, 197, 94, 0.1)' }}
                >
                  <span style={{ color: 'var(--text-muted)' }}>推定利益（総原価ベース）: </span>
                  <span style={{ color: 'var(--color-success)', fontWeight: 600 }}>
                    ${((localProduct.selling_price || 0) - (totalCost / 150)).toFixed(2)} USD
                  </span>
                  <span style={{ color: 'var(--text-muted)' }}> / </span>
                  <span style={{ color: 'var(--color-success)', fontWeight: 600 }}>
                    ¥{((localProduct.selling_price || 0) * 150 - totalCost).toLocaleString()}
                  </span>
                </div>
              )}
            </div>

            <N3Divider />

            {/* その他経費セクション */}
            <div className="py-4">
              <div className="flex items-center justify-between mb-3">
                <h4 className="text-sm font-semibold" style={{ color: 'var(--text)' }}>
                  その他経費
                </h4>
                <N3Button
                  size="sm"
                  variant="ghost"
                  onClick={handleSaveCostItems}
                  loading={savingCostItems}
                  disabled={savingCostItems}
                >
                  <Save size={14} />
                  保存
                </N3Button>
              </div>
              
              {/* 経費リスト */}
              <div className="space-y-2 mb-3">
                {costItems.map((item) => (
                  <div 
                    key={item.key}
                    className="flex items-center gap-2 p-2 rounded"
                    style={{ background: 'var(--highlight)' }}
                  >
                    <span className="flex-1 text-sm" style={{ color: 'var(--text)' }}>
                      {item.label}
                    </span>
                    <span className="text-sm font-mono" style={{ color: 'var(--text)' }}>
                      ¥{item.amount.toLocaleString()}
                    </span>
                    <button
                      onClick={() => handleRemoveCostItem(item.key)}
                      className="p-1 rounded hover:bg-[var(--panel)]"
                      style={{ color: 'var(--color-error)' }}
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                
                {costItems.length === 0 && (
                  <div 
                    className="p-3 rounded text-sm text-center"
                    style={{ background: 'var(--highlight)', color: 'var(--text-muted)' }}
                  >
                    経費が登録されていません
                  </div>
                )}
              </div>
              
              {/* 経費追加フォーム */}
              <div className="flex items-center gap-2">
                <select
                  value={newCostKey}
                  onChange={(e) => setNewCostKey(e.target.value)}
                  className="flex-1 px-2 py-1.5 rounded text-sm"
                  style={{ 
                    background: 'var(--highlight)', 
                    color: 'var(--text)',
                    border: '1px solid var(--panel-border)',
                  }}
                >
                  <option value="">項目を選択...</option>
                  {COST_ITEM_PRESETS.map((preset) => (
                    <option key={preset.key} value={preset.key}>
                      {preset.label}
                    </option>
                  ))}
                </select>
                <div className="flex items-center">
                  <span className="text-sm mr-1" style={{ color: 'var(--text-muted)' }}>¥</span>
                  <input
                    type="number"
                    value={newCostAmount}
                    onChange={(e) => setNewCostAmount(e.target.value)}
                    placeholder="金額"
                    className="w-24 px-2 py-1.5 rounded text-sm text-right"
                    style={{ 
                      background: 'var(--highlight)', 
                      color: 'var(--text)',
                      border: '1px solid var(--panel-border)',
                    }}
                  />
                </div>
                <N3Button
                  size="sm"
                  variant="ghost"
                  onClick={handleAddCostItem}
                  disabled={!newCostKey || !newCostAmount}
                >
                  <Plus size={14} />
                </N3Button>
              </div>
              
              {/* 合計 */}
              {costItems.length > 0 && (
                <div 
                  className="mt-3 p-2 rounded flex justify-between items-center"
                  style={{ background: 'rgba(245, 158, 11, 0.1)' }}
                >
                  <span className="text-sm font-medium" style={{ color: 'var(--text)' }}>
                    経費合計
                  </span>
                  <span className="text-lg font-bold" style={{ color: 'rgb(245, 158, 11)' }}>
                    ¥{totalAdditionalCosts.toLocaleString()}
                  </span>
                </div>
              )}
              
              {/* 総原価 */}
              <div 
                className="mt-2 p-2 rounded flex justify-between items-center"
                style={{ background: 'rgba(59, 130, 246, 0.1)' }}
              >
                <span className="text-sm font-medium" style={{ color: 'var(--text)' }}>
                  総原価（原価 + 経費）
                </span>
                <span className="text-lg font-bold" style={{ color: 'rgb(59, 130, 246)' }}>
                  ¥{totalCost.toLocaleString()}
                </span>
              </div>
            </div>

            <N3Divider />

            {/* L4属性: 販売予定販路 */}
            <div className="py-4">
              <div className="flex items-center justify-between mb-3">
                <h4 className="text-sm font-semibold flex items-center gap-2" style={{ color: 'var(--text)' }}>
                  <Store size={14} />
                  販売予定販路 (L4)
                </h4>
                <N3Button
                  size="sm"
                  variant="ghost"
                  onClick={handleSaveChannels}
                  loading={savingChannels}
                  disabled={savingChannels}
                >
                  <Save size={14} />
                  保存
                </N3Button>
              </div>
              
              <div className="grid grid-cols-3 gap-2">
                {(Object.entries(SALES_CHANNEL_LABELS) as [SalesChannel, string][]).map(([channel, label]) => (
                  <label
                    key={channel}
                    className="flex items-center gap-2 p-2 rounded cursor-pointer transition-all"
                    style={{ 
                      background: selectedChannels.includes(channel) 
                        ? 'rgba(59, 130, 246, 0.15)' 
                        : 'var(--highlight)',
                      border: selectedChannels.includes(channel)
                        ? '1px solid rgba(59, 130, 246, 0.5)'
                        : '1px solid transparent',
                    }}
                  >
                    <input
                      type="checkbox"
                      checked={selectedChannels.includes(channel)}
                      onChange={() => toggleChannel(channel)}
                      className="rounded"
                    />
                    <span 
                      className="text-sm"
                      style={{ 
                        color: selectedChannels.includes(channel) 
                          ? 'rgb(59, 130, 246)' 
                          : 'var(--text)',
                        fontWeight: selectedChannels.includes(channel) ? 600 : 400,
                      }}
                    >
                      {label}
                    </span>
                  </label>
                ))}
              </div>
              
              {selectedChannels.length > 0 && (
                <div className="mt-2 text-xs" style={{ color: 'var(--text-muted)' }}>
                  選択中: {selectedChannels.map(c => SALES_CHANNEL_LABELS[c]).join(', ')}
                </div>
              )}
            </div>

            <N3Divider />

            {/* 詳細情報 */}
            <div className="py-4">
              <h4 className="text-sm font-semibold mb-3" style={{ color: 'var(--text)' }}>
                詳細情報
              </h4>
              <div className="grid grid-cols-2 gap-3 text-sm">
                <div className="flex justify-between">
                  <span style={{ color: 'var(--text-muted)' }}>カテゴリ</span>
                  <span style={{ color: 'var(--text)' }}>{localProduct.category || '-'}</span>
                </div>
                <div className="flex justify-between">
                  <span style={{ color: 'var(--text-muted)' }}>マーケットプレイス</span>
                  <span style={{ color: 'var(--text)' }}>{localProduct.marketplace || '-'}</span>
                </div>
                <div className="flex justify-between">
                  <span style={{ color: 'var(--text-muted)' }}>仕入れ日</span>
                  <span style={{ color: 'var(--text)' }}>
                    {localProduct.date_acquired 
                      ? new Date(localProduct.date_acquired).toLocaleDateString('ja-JP')
                      : '-'
                    }
                  </span>
                </div>
                <div className="flex justify-between">
                  <span style={{ color: 'var(--text-muted)' }}>優先度スコア</span>
                  <span style={{ color: 'var(--text)' }}>{localProduct.priority_score || 0}</span>
                </div>
              </div>
            </div>

            {/* バリエーション情報（該当する場合） */}
            {(localProduct.is_variation_parent || localProduct.is_variation_member || localProduct.is_variation_child) && (
              <>
                <N3Divider />
                <div className="py-4">
                  <h4 className="text-sm font-semibold mb-3" style={{ color: 'var(--text)' }}>
                    バリエーション情報
                  </h4>
                  <div className="grid grid-cols-2 gap-3 text-sm">
                    <div className="flex justify-between">
                      <span style={{ color: 'var(--text-muted)' }}>親SKU</span>
                      <span style={{ color: 'var(--text)' }}>{localProduct.parent_sku || '-'}</span>
                    </div>
                  </div>
                </div>
              </>
            )}

            {/* セット商品情報（該当する場合） */}
            {localProduct.product_type === 'set' && localProduct.set_members && localProduct.set_members.length > 0 && (
              <>
                <N3Divider />
                <div className="py-4">
                  <h4 className="text-sm font-semibold mb-3" style={{ color: 'var(--text)' }}>
                    セット構成
                  </h4>
                  <div className="space-y-2">
                    {localProduct.set_members.map((member, index) => (
                      <div 
                        key={member.product_id || index}
                        className="flex items-center gap-3 p-2 rounded"
                        style={{ background: 'var(--highlight)' }}
                      >
                        <div className="flex-1 text-sm" style={{ color: 'var(--text)' }}>
                          {member.product_name || member.sku || `構成品 ${index + 1}`}
                        </div>
                        <div className="px-2 py-1 rounded text-sm font-mono" style={{ color: 'var(--text)' }}>
                          ×{member.quantity || 1}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </>
            )}

            {/* メモ */}
            {localProduct.notes && (
              <>
                <N3Divider />
                <div className="py-4">
                  <h4 className="text-sm font-semibold mb-2" style={{ color: 'var(--text)' }}>
                    メモ
                  </h4>
                  <div 
                    className="p-3 rounded text-sm"
                    style={{ background: 'var(--highlight)', color: 'var(--text-muted)' }}
                  >
                    {localProduct.notes}
                  </div>
                </div>
              </>
            )}
          </div>
        </div>

        {/* フッター */}
        <div 
          className="flex items-center justify-between px-4 py-3 border-t"
          style={{ borderColor: 'var(--panel-border)', background: 'var(--highlight)' }}
        >
          <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
            更新: {localProduct.updated_at 
              ? new Date(localProduct.updated_at).toLocaleString('ja-JP')
              : '-'
            }
          </div>
          <div className="flex gap-2">
            {localProduct.source_data?.listing_url && (
              <N3Button
                size="sm"
                variant="ghost"
                onClick={() => window.open(localProduct.source_data?.listing_url, '_blank')}
              >
                <ExternalLink size={14} />
                出品ページ
              </N3Button>
            )}
            <N3Button
              size="sm"
              variant="secondary"
              onClick={onClose}
            >
              閉じる
            </N3Button>
          </div>
        </div>
      </div>
    </div>
  );
}
